import { Component, EventEmitter, Input, Output } from '@angular/core';
import { ResumeSection } from '../../../core/models/resume.model';

@Component({
  selector: 'app-section-sidebar',
  templateUrl: './section-sidebar.component.html'
})
export class SectionSidebarComponent {
  @Input() sections: ResumeSection[] = [];
  @Input() selectedSectionId?: number;
  @Output() selectSection = new EventEmitter<number>();
  @Output() addSection = new EventEmitter<void>();
  @Output() moveUp = new EventEmitter<number>();
  @Output() moveDown = new EventEmitter<number>();
  @Output() toggleVisibility = new EventEmitter<ResumeSection>();
}
<aside class="shell-card h-fit p-4">
  <div class="flex items-center justify-between gap-3">
    <div>
      <p class="eyebrow">Sections</p>
      <p class="mt-1 text-sm text-[#667085]">Dynamic content blocks</p>
    </div>
    <button class="btn-secondary px-3 py-2 text-sm" type="button" (click)="addSection.emit()">Add Content</button>
  </div>

  <div class="mt-4 space-y-3">
    <div *ngFor="let section of sections; let i = index" class="rounded-2xl border border-[#e4e7f6] bg-[#f8f9ff] p-3">
      <button type="button" class="w-full text-left" (click)="selectSection.emit(section.id)">
        <div class="flex items-center justify-between gap-3">
          <div>
            <p class="text-sm font-semibold" [ngClass]="selectedSectionId === section.id ? 'text-[#5b5cf0]' : 'text-[#17172b]'">{{ section.sectionTitle }}</p>
            <p class="mt-1 text-xs uppercase tracking-[0.22em] text-[#7a81ad]">{{ section.sectionType }}</p>
          </div>
          <span class="rounded-full px-2 py-1 text-[10px] font-bold" [ngClass]="section.isVisible ? 'bg-[#ecfdf3] text-[#16a34a]' : 'bg-[#fff0f0] text-[#ef4444]'">
            {{ section.isVisible ? 'Visible' : 'Hidden' }}
          </span>
        </div>
      </button>
      <div class="mt-3 flex gap-2">
        <button class="btn-secondary px-3 py-2 text-xs" type="button" (click)="moveUp.emit(section.id)" [disabled]="i === 0">Up</button>
        <button class="btn-secondary px-3 py-2 text-xs" type="button" (click)="moveDown.emit(section.id)" [disabled]="i === sections.length - 1">Down</button>
        <button class="btn-secondary px-3 py-2 text-xs" type="button" (click)="toggleVisibility.emit(section)">{{ section.isVisible ? 'Hide' : 'Show' }}</button>
      </div>
    </div>
  </div>
</aside>
